private bool CanUseTrinket(int slot)
{
    return Inferno.CanUseEquippedItem(slot);
}

// Returns true if custom command is toggled on
private bool IsCustomCommandOn(string command)
{
    return Inferno.IsCustomCodeOn(command);
}

// Returns true if a talent/spell is known (for conditional talent checks)
private bool IsTalentKnown(string talentName)
{
    return Inferno.IsSpellKnown(talentName);
}

// Returns the number of enemies near player (8 yard range)
private int EnemiesNearPlayer()
{
    return Inferno.EnemiesNearUnit(8f, "player");
}

// Returns true if unit is casting an interruptible spell at or past the specified cast percentage
private bool UnitCastingAtPercent(string unit, int minPct, int maxPct = 100)
{
    // Check if unit is casting and interruptible
    if (Inferno.CastingID(unit) == 0 || !Inferno.IsInterruptable(unit))
        return false;
    
    // Calculate cast progress percentage
    int elapsed = Inferno.CastingElapsed(unit);
    int remaining = Inferno.CastingRemaining(unit);
    int total = elapsed + remaining;
    
    if (total <= 0) 
        return false;
    
    int castPct = (elapsed * 100) / total;
    
    // Check if cast is within the percentage range
    return castPct >= minPct && castPct <= maxPct;
}

// ========================================
// UNIVERSAL - INTERRUPT LOGIC
// ========================================
// Intelligent interrupt system with randomized timing
// Requires: INTERRUPT_SPELL constant, _rng, _lastCastingID, _interruptTargetPct variables in class config
// NOTE: Classes without interrupts can skip defining these - function will return false

private bool HandleInterrupt()
{
    // Skip if class doesn't have interrupt configured (healers, etc.)
    try 
    {
        if (!IsSettingOn("Auto Interrupt")) return false;
    }
    catch 
    {
        // Setting doesn't exist - this class doesn't use interrupts
        return false;
    }

    int castingID = TargetCastingID();
    if (!TargetIsCasting())
    {
        _lastCastingID = 0;
        return false;
    }

    // New cast started - randomize interrupt percentage
    if (castingID != _lastCastingID)
    {
        _lastCastingID = castingID;
        int minPct = GetSlider("Interrupt at cast % (min)");
        int maxPct = GetSlider("Interrupt at cast % (max)");
        if (maxPct < minPct) maxPct = minPct;
        _interruptTargetPct = _rng.Next(minPct, maxPct + 1);
    }

    // Calculate cast progress percentage
    int elapsed = CastingElapsed();
    int remaining = CastingRemaining();
    int total = elapsed + remaining;
    if (total <= 0) return false;

    int castPct = (elapsed * 100) / total;

    // Interrupt at randomized percentage
    if (castPct >= _interruptTargetPct && Inferno.CanCast(INTERRUPT_SPELL, IgnoreGCD: true))
    {
        Log("Interrupting at " + castPct + "% (target: " + _interruptTargetPct + "%)");
        Inferno.Cast(INTERRUPT_SPELL, QuickDelay: true);
        _lastCastingID = 0;
        return true;
    }

    return false;
}

// ========================================
// UNIVERSAL - INTERRUPT LOGIC
// ========================================
// Intelligent interrupt system with randomized timing
// Requires: INTERRUPT_SPELL constant, _rng, _lastCastingID, _interruptTargetPct variables in class config
// NOTE: Classes without interrupts can skip defining these - function will return false

private bool HandleInterrupt()
{
    // Skip if class doesn't have interrupt configured (healers, etc.)
    try 
    {
        if (!IsSettingOn("Auto Interrupt")) return false;
    }
    catch 
    {
        // Setting doesn't exist - this class doesn't use interrupts
        return false;
    }

    int castingID = Inferno.CastingID(unit);
    if (!Inferno.IsInterruptable(unit) || castingID == 0)
    {
        // Clear tracking when not casting
        if (_interruptTracking.ContainsKey(unit))
            _interruptTracking.Remove(unit);
        return false;
    }

    // Get or initialize tracking for this unit
    if (!_interruptTracking.ContainsKey(unit) || _interruptTracking[unit].CastID != castingID)
    {
        // New cast started - randomize interrupt percentage
        int minPct = GetSlider("Interrupt at cast % (min)");
        int maxPct = GetSlider("Interrupt at cast % (max)");
        if (maxPct < minPct) maxPct = minPct;
        int targetPct = _rng.Next(minPct, maxPct + 1);
        _interruptTracking[unit] = new InterruptState(castingID, targetPct);
    }

    int interruptPct = _interruptTracking[unit].TargetPct;

    // Check if we've reached the interrupt percentage
    if (UnitCastingAtPercent(unit, interruptPct) && Inferno.CanCast(spell, IgnoreGCD: true))
    {
        // Calculate actual cast percentage for logging
        int elapsed = Inferno.CastingElapsed(unit);
        int remaining = Inferno.CastingRemaining(unit);
        int total = elapsed + remaining;
        int castPct = total > 0 ? (elapsed * 100) / total : 0;

        Log("Interrupting " + unit + " at " + castPct + "% (target: " + interruptPct + "%)");
        Inferno.Cast(spell, QuickDelay: true);
        _interruptCastID.Remove(unit);
        _interruptTargetPct.Remove(unit);
        return true;
    }

    return false;
}

// Condition: Returns true if unit is casting and has reached the target interrupt percentage
// Can be used with randomized or fixed percentages for defensive reactions
private bool ShouldInterruptCast(string unit, int minPct, int maxPct = 100)
{
    return UnitCastingAtPercent(unit, minPct, maxPct);
}

// ========================================
// EXAMPLE: USING INTERRUPT CONDITIONS FOR DEFENSIVE REACTIONS
// ========================================
// This example shows how to use the UnitCastingAtPercent condition
// for reactive defensive abilities (not just interrupts)

// Example 1: Aura Mastery on boss cast (30% into cast)
private bool HandleBossDefensives()
{
    // Use Aura Mastery when boss1 starts casting (30% progress)
    if (Inferno.UnitExists("boss1") && UnitCastingAtPercent("boss1", 30) && CanCastSpell("Aura Mastery"))
    {
        Log("Boss1 casting detected at 30% - using Aura Mastery");
        Inferno.Cast("Aura Mastery");
        return true;
    }

    // Use Divine Shield when boss2 is 20-40% into a dangerous cast
    if (Inferno.UnitExists("boss2") && UnitCastingAtPercent("boss2", 20, 40) && CanCastSpell("Divine Shield"))
    {
        string spellName = Inferno.CastingName("boss2");
        Log("Boss2 casting " + spellName + " - using Divine Shield");
        Inferno.Cast("Divine Shield");
        return true;
    }

    return false;
}

// Example 2: Protect allies from boss casts
private bool ProtectAllyFromBossCast()
{
    // Check if any boss is casting
    for (int i = 1; i <= 5; i++)
    {
        string boss = "boss" + i;
        if (!Inferno.UnitExists(boss)) continue;

        // Boss is 25% into cast - protect focus
        if (UnitCastingAtPercent(boss, 25) && Inferno.UnitExists("focus"))
        {
            // Use Blessing of Protection on focus
            if (CanCastSpell("Blessing of Protection"))
            {
                Log("Protecting focus from " + boss + " cast");
                Inferno.Cast("Blessing of Protection", "focus");
                return true;
            }

            // Or use Pain Suppression (Priest)
            if (CanCastSpell("Pain Suppression"))
            {
                Log("Using Pain Suppression on focus (" + boss + " casting)");
                Inferno.Cast("Pain Suppression", "focus");
                return true;
            }
        }
    }

    return false;
}

// Example 3: Interrupt specific spells at specific percentages
private bool SmartInterrupt()
{
    string targetSpell = Inferno.CastingName("target");

    // Interrupt Pyroblast late (70-90%) to bait
    if (targetSpell == "Pyroblast" && UnitCastingAtPercent("target", 70, 90))
    {
        if (CanCast("Kick", "target"))
        {
            Log("Interrupting Pyroblast at 70-90%");
            Inferno.Cast("Kick");
            return true;
        }
    }

    // Interrupt Polymorph early (20-40%) to prevent CC
    if (targetSpell == "Polymorph" && UnitCastingAtPercent("target", 20, 40))
    {
        if (CanCast("Kick", "target"))
        {
            Log("Interrupting Polymorph early (20-40%)");
            Inferno.Cast("Kick");
            return true;
        }
    }

    // Default interrupt using randomized percentage from settings
    return HandleInterrupt();
}

// Example 4: Multi-target interrupt priority
private bool MultiTargetInterruptPriority()
{
    // Priority 1: Interrupt focus if casting (they're our kill target)
    if (Inferno.UnitExists("focus") && UnitCastingAtPercent("focus", 30, 80))
    {
        if (CanCast("Kick", "focus"))
        {
            Log("Interrupting focus cast (priority target)");
            Inferno.Cast("Kick", "focus");
            return true;
        }
    }

    // Priority 2: Interrupt current target
    if (UnitCastingAtPercent("target", 40, 90))
    {
        if (CanCast("Kick", "target"))
        {
            Log("Interrupting target cast");
            Inferno.Cast("Kick");
            return true;
        }
    }

    // Priority 3: Check arena enemies (arena1, arena2, arena3)
    for (int i = 1; i <= 3; i++)
    {
        string arena = "arena" + i;
        if (Inferno.UnitExists(arena) && UnitCastingAtPercent(arena, 35, 85))
        {
            if (CanCast("Kick", arena))
            {
                Log("Interrupting " + arena + " cast");
                Inferno.Cast("Kick", arena);
                return true;
            }
        }
    }

    return false;
}

// Example 5: Condition-based defensive selection
private bool SmartDefensiveCooldowns()
{
    // Low health + boss casting = emergency defensive
    if (HealthPct("player") < 40)
    {
        for (int i = 1; i <= 5; i++)
        {
            string boss = "boss" + i;
            if (!Inferno.UnitExists(boss)) continue;

            // Boss is 15-35% into cast and we're low
            if (UnitCastingAtPercent(boss, 15, 35))
            {
                // Use strongest defensive available
                if (CanCastSpell("Divine Shield"))
                {
                    Log("Emergency: Boss casting while low HP - Divine Shield");
                    Inferno.Cast("Divine Shield");
                    return true;
                }

                if (CanCastSpell("Dispersion"))
                {
                    Log("Emergency: Boss casting while low HP - Dispersion");
                    Inferno.Cast("Dispersion");
                    return true;
                }

                if (CanCastSpell("Ice Block"))
                {
                    Log("Emergency: Boss casting while low HP - Ice Block");
                    Inferno.Cast("Ice Block");
                    return true;
                }
            }
        }
    }

    return false;
}

// Example 6: Using with ShouldInterruptCast alias (more semantic for defensives)
private bool HandleDefensiveReactions()
{
    // ShouldInterruptCast is an alias for UnitCastingAtPercent
    // Use it when the semantic meaning is "should I react to this cast"

    if (ShouldInterruptCast("boss1", 30, 50) && CanCastSpell("Aura Mastery"))
    {
        Log("Reacting to boss1 cast with Aura Mastery");
        Inferno.Cast("Aura Mastery");
        return true;
    }

    return false;
}

// Example 7: Integration with existing rotation
private bool ExecuteDamageRotation()
{
    // Check for defensive reactions first
    if (HandleBossDefensives())
        return true;

    if (ProtectAllyFromBossCast())
        return true;

    // Then handle interrupts
    if (SmartInterrupt())
        return true;

    // Continue with normal rotation...
    // ... your damage spells here ...

    return false;
}

# Interrupt/Cast Percentage Condition Usage Guide

## Overview
The interrupt system has been refactored into a flexible condition that can be used for various reactive abilities, not just interrupts.

## Components

### 1. UnitCastingAtPercent Condition (01_Conditions.cs)
```csharp
private bool UnitCastingAtPercent(string unit, int minPct, int maxPct = 100)
```
- **Purpose**: Returns true if the specified unit is casting an interruptible spell and the cast progress is within the percentage range
- **Parameters**:
  - `unit`: The unit to check ("target", "boss1", "focus", etc.)
  - `minPct`: Minimum cast percentage (0-100)
  - `maxPct`: Maximum cast percentage (0-100), defaults to 100
- **Returns**: `true` if unit is casting and cast is between minPct and maxPct

### 2. HandleInterruptOnUnit Function (04_Interrupt.cs)
```csharp
private bool HandleInterruptOnUnit(string unit, string spell)
```
- **Purpose**: Interrupt a unit's cast with randomized timing based on settings
- **Parameters**:
  - `unit`: The unit to interrupt ("target", "boss1", etc.)
  - `spell`: The spell to use for interrupting
- **Uses settings**: 
  - "Auto Interrupt" (checkbox)
  - "Interrupt at cast % (min)" (slider)
  - "Interrupt at cast % (max)" (slider)

### 3. ShouldInterruptCast Condition (04_Interrupt.cs)
```csharp
private bool ShouldInterruptCast(string unit, int minPct, int maxPct = 100)
```
- **Purpose**: Alias for `UnitCastingAtPercent` - more semantic name for defensive use cases
- **Parameters**: Same as `UnitCastingAtPercent`

## Usage Examples

### Example 1: Basic Interrupt on Target
```csharp
// In your damage rotation:
if (HandleInterrupt())
    return true;
```

### Example 2: Interrupt Boss1
```csharp
// Interrupt boss1 when they're 40-90% through their cast
if (HandleInterruptOnUnit("boss1", "Wind Shear"))
    return true;
```

### Example 3: Defensive Cooldown on Boss Cast
```csharp
// Use Aura Mastery when boss1 is 30% into casting
if (ShouldInterruptCast("boss1", 30) && CanCastSpell("Aura Mastery"))
{
    Log("Boss casting detected - using Aura Mastery");
    return CastPersonal("Aura Mastery");
}
```

### Example 4: React to Specific Cast Percentage Range
```csharp
// Use defensive when boss is between 20-40% on their cast
if (UnitCastingAtPercent("boss1", 20, 40) && CanCastSpell("Divine Shield"))
{
    Log("Boss dangerous cast detected early - using Divine Shield");
    return CastPersonal("Divine Shield");
}
```

### Example 5: Multiple Boss Unit Checks
```csharp
// Check multiple boss units for dangerous casts
for (int i = 1; i <= 5; i++)
{
    string boss = "boss" + i;

    // React early to dangerous casts (10-30%)
    if (UnitCastingAtPercent(boss, 10, 30) && Inferno.UnitExists(boss))
    {
        if (CanCastSpell("Aura Mastery"))
        {
            Log("Detected dangerous cast from " + boss + " - using Aura Mastery");
            return CastPersonal("Aura Mastery");
        }
    }
}
```

### Example 6: Ally Protection
```csharp
// Protect focus target when boss is casting at them
if (UnitCastingAtPercent("boss1", 40) && CanCastSpell("Blessing of Protection"))
{
    if (Inferno.UnitExists("focus") && !Inferno.IsDead("focus"))
    {
        Log("Protecting focus from boss cast");
        return CastOnUnit("Blessing of Protection", "focus");
    }
}
```

### Example 7: Conditional Interrupt Based on Cast Name
```csharp
// Only interrupt specific spells at certain percentages
if (Inferno.CastingName("target") == "Pyroblast" && UnitCastingAtPercent("target", 70))
{
    if (CanCast("Kick", "target"))
    {
        Log("Interrupting Pyroblast at 70%+");
        Inferno.Cast("Kick");
        return true;
    }
}
```

## Configuration Requirements

To use the interrupt system, your class config (10_Config.cs) needs:

```csharp
// For classes WITH interrupts (DPS/Tank):
private const string INTERRUPT_SPELL = "YourInterruptSpellName";
private Random _rng = new Random();

// Settings in LoadSettings():
Settings.Add(new Setting("Auto Interrupt", true));
Settings.Add(new Setting("Interrupt at cast % (min)", 0, 100, 40));
Settings.Add(new Setting("Interrupt at cast % (max)", 0, 100, 90));
```

For classes without interrupts (healers), you can still use the condition functions:
```csharp
// Minimal config for healers using reactive defensives:
private Random _rng = new Random();
private const string INTERRUPT_SPELL = ""; // Not used but required by component
```

## Tracking System

The interrupt handler uses a dictionary to track each unit independently:
```csharp
private Dictionary<string, (int castID, int targetPct)> _interruptTracking = new Dictionary<string, (int, int)>();
```

This allows:
- Multiple units to be tracked simultaneously (target, boss1, boss2, etc.)
- Each cast gets a new randomized percentage
- Clean state management when casts finish or are interrupted

## Best Practices

1. **Early Detection for Defensives**: Use low percentages (10-30%) for defensive cooldowns to react quickly
2. **Late Interrupt for DPS**: Use higher percentages (40-90%) for interrupts to bait enemy fakes
3. **Range Checks**: Use min/max ranges to create windows of opportunity
4. **Spell Name Filtering**: Combine with `Inferno.CastingName()` to react to specific spells
5. **Priority Systems**: Check dangerous bosses/spells first before falling back to general interrupts

# Quick Reference: UnitCastingAtPercent Condition

## Function Signature
```csharp
private bool UnitCastingAtPercent(string unit, int minPct, int maxPct = 100)
```

## Parameters
- **unit**: Unit to check ("target", "boss1", "boss2", "focus", "arena1", etc.)
- **minPct**: Minimum cast percentage (0-100)
- **maxPct**: Maximum cast percentage (0-100), optional, defaults to 100

## Returns
- `true` if unit is casting an interruptible spell AND cast progress is >= minPct AND <= maxPct
- `false` otherwise

